BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?verification ?vName ?type ?other ?oName WHERE {
  ?verification rdf:type vocab:verify .
  OPTIONAL { ?verification vocab:NamedElement_name ?vName }

  ?verification vocab:Dependency_client ?client .
  ?client vocab:NamedElement_name ?oName .

  OPTIONAL { ?verification rdf:type ?type }
  FILTER(CONTAINS(LCASE(STR(?oName)), LCASE("post")) || CONTAINS(LCASE(STR(?oName)), LCASE("segment")))

  OPTIONAL { ?verification vocab:Dependency_supplier ?other . }
  OPTIONAL { ?other vocab:NamedElement_name ?otherName . BIND(?otherName AS ?oName) }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?psElem ?psName ?activity ?actName ?actType WHERE {
  ?psElem rdf:type vocab:tmt%20requirement .
  ?psElem vocab:NamedElement_name ?psName .
  FILTER(
    CONTAINS(LCASE(STR(?psName)), LCASE("post")) &&
    CONTAINS(LCASE(STR(?psName)), LCASE("segment"))
  )

  # Included activities are typically modeled via satisfy/verify patterns
  # try both: psElem --satisfy--> activity, and psElem --verify--> activity
  OPTIONAL {
    ?psElem (vocab:satisfy|vocab:verify) ?activity .
    OPTIONAL { ?activity vocab:NamedElement_name ?actName . }
    OPTIONAL { ?activity rdf:type ?actType . }
  }

  FILTER(BOUND(?activity))

  OPTIONAL { ?activity vocab:NamedElement_name ?actName . }
  OPTIONAL { ?activity rdf:type ?actType . }
}
LIMIT 25
